using UnityEngine;

public class RigidbodyExample : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float jumpForce = 10f;
    public float rotationSpeed = 100f;

    private Rigidbody2D rb;
    private bool isGrounded;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
        if (rb == null)
        {
            Debug.LogError("Rigidbody2D is required!");
        }
    }

    void Update()
    {
        // Movement using velocity (direct control)
        float horizontal = Input.GetAxis("Horizontal");
        rb.velocity = new Vector2(horizontal * moveSpeed, rb.velocity.y);

        // Jump using AddForce (impulse)
        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
            isGrounded = false;
        }

        // Rotation using torque (smooth rotation)
        if (Input.GetKey(KeyCode.Q))
        {
            rb.AddTorque(rotationSpeed * Time.deltaTime);
        }
        if (Input.GetKey(KeyCode.E))
        {
            rb.AddTorque(-rotationSpeed * Time.deltaTime);
        }
    }

    void OnCollisionEnter2D(Collision2D collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            isGrounded = true;
        }
    }

    // Example: Apply force in a direction
    public void ApplyForce(Vector2 direction, float force)
    {
        rb.AddForce(direction * force, ForceMode2D.Force);
    }

    // Example: Apply impulse (instant burst)
    public void ApplyImpulse(Vector2 direction, float force)
    {
        rb.AddForce(direction * force, ForceMode2D.Impulse);
    }

    // Example: Set velocity directly
    public void SetVelocity(Vector2 velocity)
    {
        rb.velocity = velocity;
    }
}

